module RefModule(
    /* Input ports */
    input [7:0] in,
    /* Output ports */
    output reg [3:0] out
);integer obf_i;
reg [3:0] count;

always @ (*) begin
    count = 0;
    for (obf_i = 0; obf_i < 8; obf_i = obf_i + 1) begin
        if (in[obf_i] == 1) begin
            count = count + 1;
        end
    end
    out = count;
end

endmodule
